import { toServerOption } from '../options/option.js';
export const toServerForm = (localize, type, form) => ({
    type,
    title: localize(form.title),
    icon: form.icon,
    description: form.description && localize(form.description),
    help: form.help && localize(form.help),
    requireConfirmation: form.requireConfirmation,
    options: Object.entries(form.options).map(([query, option]) => toServerOption(localize, query, option)),
});
export const toServerForms = (localize, pick, forms) => Object.entries(pick)
    .map(([type, value]) => 
// eslint-disable-next-line @typescript-eslint/no-non-null-assertion
value && toServerForm(localize, type, value === true ? forms[type] : value))
    .filter((form) => !!form);
